import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const ORANGE = '#FF6B00';
const DARK = '#1a1a2e';
const WHITE = '#ffffff';

const MY_BOOKINGS = [
  { id: 'BP0VVCUTP', car: 'Kwid RXE-10', img: 'https://images.unsplash.com/photo-1502877338535-766e1452684a?w=80&q=80', from: '2024-04-01', to: '2024-04-03', days: 3, price: 12000, status: 'Pending', vehicle: 'NA', payment: 'Pending' },
  { id: 'PQTLLUKPU', car: 'Tata Nexon Pro', img: 'https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=80&q=80', from: '2024-03-29', to: '2024-03-31', days: 3, price: 7500, status: 'Paid & Confirmed', vehicle: 'MH03***920', payment: 'Paid' },
  { id: '5HCDIGZCY', car: 'Thar', img: 'https://images.unsplash.com/photo-1533473359331-0135ef1b58bf?w=80&q=80', from: '2024-03-24', to: '2024-03-25', days: 2, price: 7000, status: 'Cancelled', vehicle: 'NA', payment: 'Pending' },
];

function getStatusStyle(status) {
  switch (status) {
    case 'Approved': return { background: '#e0f2fe', color: '#0369a1' };
    case 'Cancelled': return { background: '#fee2e2', color: '#dc2626' };
    case 'Paid & Confirmed': return { background: '#dcfce7', color: '#16a34a' };
    case 'Pending': return { background: '#fef9c3', color: '#ca8a04' };
    default: return { background: '#f3f4f6', color: '#6b7280' };
  }
}

export default function CustomerBookingsPage() {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState(MY_BOOKINGS);

  useEffect(() => {
    const link = document.createElement('link');
    link.href = 'https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700;800;900&display=swap';
    link.rel = 'stylesheet';
    document.head.appendChild(link);
